// 'active' (covers the resurrect-a-deleted-file case, not just plain edits).
func (q *Queries) UpdateEpisodeContent(ctx context.Context, arg UpdateEpisodeContentParams) error {
	_, err := q.db.ExecContext(ctx, updateEpisodeContent,
		arg.SourceHash,
		arg.SourceTier,
		arg.Status,
		arg.ID,
	)
	return err
}

const updateEvalLabelAnswer = `-- name: UpdateEvalLabelAnswer :exec
UPDATE eval_labels
SET label = ?, answered_at = ?
WHERE id = ?
`

type UpdateEvalLabelAnswerParams struct {
	Label      sql.NullString `json:"label"`
	AnsweredAt sql.NullString `json:"answered_at"`
	ID         int64          `json:"id"`
}

// Edits label/answered_at IN PLACE (W5-03 task spec: "multiple taps on
// the same question edit the label, they do not append evidence rows") -
// called again on a later, possibly-different-button tap for the SAME
// question; this never creates a second eval_labels row for one asked
// fact.
func (q *Queries) UpdateEvalLabelAnswer(ctx context.Context, arg UpdateEvalLabelAnswerParams) error {
	_, err := q.db.ExecContext(ctx, updateEvalLabelAnswer, arg.Label, arg.AnsweredAt, arg.ID)
	return err
}

const updateFactConfidence = `-- name: UpdateFactConfidence :exec
UPDATE facts SET confidence = ?, updated_at = ? WHERE id = ?
`

type UpdateFactConfidenceParams struct {
	Confidence float64 `json:"confidence"`
	UpdatedAt  string  `json:"updated_at"`
	ID         int64   `json:"id"`
}

// The engine recomputes confidence from the fact's own evidence rows
// (sum of weights, deduped by (session_id, polarity), clamped to the
// highest positive tier cap represented - never a noisy-OR ratchet) and
// writes the result back here after every WriteFact/DenyFact call.
func (q *Queries) UpdateFactConfidence(ctx context.Context, arg UpdateFactConfidenceParams) error {
	_, err := q.db.ExecContext(ctx, updateFactConfidence, arg.Confidence, arg.UpdatedAt, arg.ID)
	return err
}

const updateTaskSession = `-- name: UpdateTaskSession :exec
UPDATE tasks
SET session_id = ?, updated_at = ?
WHERE id = ?
`

type UpdateTaskSessionParams struct {
	SessionID sql.NullString `json:"session_id"`
	UpdatedAt string         `json:"updated_at"`
	ID        string         `json:"id"`
}

// Persists a worker-reported session_id onto the task row (W12-07 step 3:
// kahyad "persists session_id onto the task row" as the worker's
// {"type":"session",...} stdout line arrives). Session RESUME itself
// (using a stored session_id to continue a LATER task) is W4-02; this
// query only records the value as it arrives.
func (q *Queries) UpdateTaskSession(ctx context.Context, arg UpdateTaskSessionParams) error {
	_, err := q.db.ExecContext(ctx, updateTaskSession, arg.SessionID, arg.UpdatedAt, arg.ID)
	return err
}

